// docent.config.ts -- repo-root extension point for the brand-pack tutorial.
//
// The CLI walks UP from cwd looking for the first docent.config.{ts,tsx,js,mjs}.
// When found, the default export's `plugins` array is registered on top of
// @bjelser/core's corePlugins. The file IS the third-party-pack on-ramp.

import {tutorialBrandPreset} from './tutorials/brand-pack/presets/tutorial-brand';

export default {
  plugins: [tutorialBrandPreset],
};

import type {DesignTokens} from '@bjelser/kit';

export const tokens: DesignTokens = {
  bg: {
    base: '#f4ecd8',     // IVORY -- the page itself
    panel: '#fbf6ea',    // raised paper
    panelHi: '#ffffff',  // the focused panel
    void: '#e8e1d2', line: '#c7b994', lineHi: '#a89469',
  },
  ink: {
    hi:  '#10142b',      // deep navy-graphite -- the headline ink
    mid: '#2c324a', low: '#5b6275', faint: '#8d92a3',
  },
  accent: {
    rose:  '#a8232e',    // CRIMSON -- the headline accent
    blue:  '#1d3b6e',    // ink blue -- the secondary brand
    green: '#3f6b3a', amber: '#c2913d',
    cyan:  '#5d7da3', violet: '#6e3a78',
  },
  typography: {
    family: {
      sans:  'Fjalla One, Oswald, sans-serif',      // condensed chrome
      serif: 'Lora, Source Serif Pro, serif',       // transitional body
      mono:  'JetBrains Mono, monospace',
    },
    size: {body: 19, heading: 34, display: 64, label: 21, small: 14, micro: 12},
    weight: {body: 400, label: 500, heading: 700, display: 800},
    lineHeight: 1.6,
    letterSpacing: 0,
  },
  spacing: {xs: 4, sm: 8, md: 16, lg: 24, xl: 40, gutter: 32},
  radius:  {sm: 2, md: 4, lg: 8},
  stroke:  {hairline: 0.75, thin: 1, regular: 1.5, bold: 2.5},
};
